export interface PetStats {
    hp: number;
    mp: number;
    atk: number;
    def: number;
    spd: number;
}

export interface PetGrowthRates {
    hp: number;
    mp: number;
    atk: number;
    def: number;
    spd: number;
}

export interface PetData {
    id: string;
    name: string;
    description: string;
    icon: string;
    type: string;
    rarity: string;
    baseStats: PetStats;
    skills: string[];
    growthRates: PetGrowthRates;
}

export interface PetInstance {
    id: string;
    name: string;
    data: PetData;
    level: number;
    exp: number;
    expToNext: number;
    stats: PetStats;
    maxStats: PetStats;
    currentHp: number;
    currentMp: number;
    skills: string[];
    mood: number;
    hunger: number;
    affection: number;
    enterBattle(): void;
    leaveBattle(): void;
    isDead(): boolean;
    takeTurn(): void;
    useSkill(skillId: string): void;
    gainExp(amount: number): void;
    levelUp(): void;
    heal(amount: number): void;
    damage(amount: number): void;
    feed(item: { hungerRestore: number; affectionRestore: number }): void;
    play(): void;
    getStatus(): string;
}

export class PetSystem {
    private isInitialized: boolean = false;
    private playerPets: PetInstance[] = [];
    private activePet: PetInstance | null = null;
    private petData: Map<string, PetData> = new Map();

    constructor() {
        this.isInitialized = false;
        this.playerPets = [];
        this.activePet = null;
    }

    async init(): Promise<void> {
        this.loadPetData();
        this.loadPlayerPets();
        this.isInitialized = true;
        console.log('[PetSystem] 宠物系统初始化完成');
    }

    private loadPetData(): void {
        this.registerPet({
            id: 'slime_blue',
            name: '蓝史莱姆',
            description: '可爱的小史莱姆，会为你恢复少量生命',
            icon: '🟦',
            type: 'healer',
            rarity: 'common',
            baseStats: { hp: 50, mp: 30, atk: 5, def: 5, spd: 10 },
            skills: ['slime_heal', 'slime_bounce'],
            growthRates: { hp: 1.2, mp: 1.0, atk: 0.8, def: 1.0, spd: 1.2 }
        });

        this.registerPet({
            id: 'wolf_pup',
            name: '狼崽',
            description: '幼年的狼，速度快，攻击力强',
            icon: '🐺',
            type: 'attacker',
            rarity: 'common',
            baseStats: { hp: 60, mp: 20, atk: 15, def: 5, spd: 15 },
            skills: ['bite', 'howl'],
            growthRates: { hp: 1.1, mp: 0.8, atk: 1.3, def: 0.9, spd: 1.3 }
        });

        this.registerPet({
            id: 'baby_dragon',
            name: '幼龙',
            description: '小型龙族，拥有强大的潜力',
            icon: '🐉',
            type: 'balanced',
            rarity: 'rare',
            baseStats: { hp: 80, mp: 50, atk: 12, def: 10, spd: 8 },
            skills: ['dragon_breath', 'tail_whip'],
            growthRates: { hp: 1.3, mp: 1.2, atk: 1.2, def: 1.2, spd: 1.0 }
        });

        this.registerPet({
            id: 'fairy',
            name: '精灵',
            description: '发光的小精灵，能提供强力支援',
            icon: '🧚',
            type: 'support',
            rarity: 'rare',
            baseStats: { hp: 40, mp: 80, atk: 8, def: 5, spd: 20 },
            skills: ['fairy_dust', 'heal_light'],
            growthRates: { hp: 0.9, mp: 1.5, atk: 0.9, def: 0.8, spd: 1.4 }
        });

        this.registerPet({
            id: 'golem_small',
            name: '小型魔像',
            description: '坚固的魔像，优秀的防御者',
            icon: '🗿',
            type: 'tank',
            rarity: 'rare',
            baseStats: { hp: 120, mp: 10, atk: 8, def: 20, spd: 3 },
            skills: ['rock_throw', 'stone_skin'],
            growthRates: { hp: 1.5, mp: 0.5, atk: 0.8, def: 1.5, spd: 0.6 }
        });

        this.registerPet({
            id: 'phoenix_chick',
            name: '凤雏',
            description: '幼年的凤凰，拥有重生的力量',
            icon: '🔥',
            type: 'special',
            rarity: 'epic',
            baseStats: { hp: 70, mp: 60, atk: 15, def: 8, spd: 12 },
            skills: ['fire_breath', 'rebirth_ash'],
            growthRates: { hp: 1.2, mp: 1.3, atk: 1.3, def: 1.0, spd: 1.2 }
        });

        this.registerPet({
            id: 'shadow_cat',
            name: '影猫',
            description: '神秘的影猫，潜行与暗杀专家',
            icon: '🐱',
            type: 'assassin',
            rarity: 'epic',
            baseStats: { hp: 50, mp: 40, atk: 20, def: 6, spd: 25 },
            skills: ['shadow_strike', 'vanish'],
            growthRates: { hp: 1.0, mp: 1.1, atk: 1.4, def: 0.8, spd: 1.5 }
        });

        this.registerPet({
            id: 'light_wisp',
            name: '光之精灵',
            description: '纯光构成的生物，神圣而强大',
            icon: '✨',
            type: 'holy',
            rarity: 'legendary',
            baseStats: { hp: 100, mp: 100, atk: 18, def: 15, spd: 15 },
            skills: ['holy_light', 'divine_shield', 'purify'],
            growthRates: { hp: 1.4, mp: 1.4, atk: 1.4, def: 1.3, spd: 1.3 }
        });
    }

    private registerPet(pet: PetData): void {
        this.petData.set(pet.id, pet);
    }

    private createPetInstance(petId: string): PetInstance | null {
        const petData = this.petData.get(petId);
        if (!petData) return null;

        const self = this;

        return {
            id: petId,
            name: petData.name,
            data: petData,
            level: 1,
            exp: 0,
            expToNext: 100,
            stats: { ...petData.baseStats },
            maxStats: { ...petData.baseStats },
            currentHp: petData.baseStats.hp,
            currentMp: petData.baseStats.mp,
            skills: [...petData.skills],
            mood: 80,
            hunger: 100,
            affection: 50,

            enterBattle(): void {
                this.currentHp = this.stats.hp;
                this.currentMp = this.stats.mp;
            },

            leaveBattle(): void {},

            isDead(): boolean {
                return this.currentHp <= 0;
            },

            takeTurn(): void {
                const skillId = this.skills[Math.floor(Math.random() * this.skills.length)];
                this.useSkill(skillId);
            },

            useSkill(skillId: string): void {
                console.log(`${this.name} 使用了 ${skillId}`);
            },

            gainExp(amount: number): void {
                this.exp += amount;
                if (this.exp >= this.expToNext) {
                    this.levelUp();
                }
            },

            levelUp(): void {
                this.level++;
                this.exp -= this.expToNext;
                this.expToNext = Math.floor(this.expToNext * 1.5);

                const rates = this.data.growthRates;
                this.stats.hp = Math.floor(this.stats.hp * rates.hp);
                this.stats.mp = Math.floor(this.stats.mp * rates.mp);
                this.stats.atk = Math.floor(this.stats.atk * rates.atk);
                this.stats.def = Math.floor(this.stats.def * rates.def);
                this.stats.spd = Math.floor(this.stats.spd * rates.spd);

                this.maxStats = { ...this.stats };

                const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
                win.game?.showNotification?.(`${this.name} 升到了 ${this.level} 级！`, 'success');
            },

            heal(amount: number): void {
                this.currentHp = Math.min(this.currentHp + amount, this.stats.hp);
            },

            damage(amount: number): void {
                this.currentHp = Math.max(0, this.currentHp - amount);
            },

            feed(item: { hungerRestore: number; affectionRestore: number }): void {
                this.hunger = Math.min(100, this.hunger + item.hungerRestore);
                this.affection = Math.min(100, this.affection + item.affectionRestore);
                const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
                win.game?.showNotification?.(`${this.name} 吃得很开心！`, 'success');
            },

            play(): void {
                this.mood = Math.min(100, this.mood + 20);
                this.affection = Math.min(100, this.affection + 5);
                const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
                win.game?.showNotification?.(`${this.name} 玩得很开心！`, 'success');
            },

            getStatus(): string {
                if (this.hunger < 30) return 'hungry';
                if (this.mood < 30) return 'unhappy';
                if (this.affection > 80) return 'loved';
                return 'normal';
            }
        };
    }

    addPet(petId: string): boolean {
        const petInstance = this.createPetInstance(petId);
        if (!petInstance) return false;

        this.playerPets.push(petInstance);
        this.savePlayerPets();

        const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
        win.game?.showNotification?.(`获得了 ${petInstance.name}！`, 'success');
        return true;
    }

    removePet(petIndex: number): boolean {
        if (petIndex < 0 || petIndex >= this.playerPets.length) return false;

        const pet = this.playerPets[petIndex];
        if (this.activePet === pet) {
            this.activePet = null;
        }

        this.playerPets.splice(petIndex, 1);
        this.savePlayerPets();
        return true;
    }

    setActivePet(petIndex: number): boolean {
        if (petIndex < 0 || petIndex >= this.playerPets.length) return false;

        this.activePet = this.playerPets[petIndex];
        const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
        win.game?.showNotification?.(`${this.activePet.name} 已设置为出战宠物！`, 'success');
        this.savePlayerPets();
        return true;
    }

    getPetData(petId: string): PetData | undefined {
        return this.petData.get(petId);
    }

    getPlayerPets(): PetInstance[] {
        return this.playerPets;
    }

    getActivePet(): PetInstance | null {
        return this.activePet;
    }

    feedPet(petIndex: number, item: { hungerRestore: number; affectionRestore: number }): boolean {
        if (petIndex < 0 || petIndex >= this.playerPets.length) return false;

        const pet = this.playerPets[petIndex];
        pet.feed(item);
        this.savePlayerPets();
        return true;
    }

    playWithPet(petIndex: number): boolean {
        if (petIndex < 0 || petIndex >= this.playerPets.length) return false;

        const pet = this.playerPets[petIndex];
        pet.play();
        this.savePlayerPets();
        return true;
    }

    renderPetList(): void {
        const container = document.getElementById('pet-list');
        if (!container) return;

        container.innerHTML = '';

        this.playerPets.forEach((pet, index) => {
            const petElement = document.createElement('div');
            petElement.className = 'pet-card';
            const isActive = this.activePet === pet;

            petElement.innerHTML = `
                <div class="pet-icon">${pet.data.icon}</div>
                <div class="pet-info">
                    <div class="pet-name">${pet.name} Lv.${pet.level}</div>
                    <div class="pet-status">${pet.getStatus()}</div>
                    <div class="pet-bars">
                        <div class="bar-container">
                            <div class="bar-fill hp" style="width: ${(pet.currentHp / pet.stats.hp) * 100}%"></div>
                        </div>
                        <div class="bar-container">
                            <div class="bar-fill mood" style="width: ${pet.mood}%"></div>
                        </div>
                    </div>
                </div>
                <div class="pet-actions">
                    <button class="btn btn-small" onclick="petSystem.feedPet(${index}, {hungerRestore: 30, affectionRestore: 5})">喂食</button>
                    <button class="btn btn-small" onclick="petSystem.playWithPet(${index})">玩耍</button>
                    ${!isActive ? `<button class="btn btn-small btn-primary" onclick="petSystem.setActivePet(${index})">出战</button>` : ''}
                </div>
            `;

            if (isActive) {
                petElement.classList.add('active');
            }

            container.appendChild(petElement);
        });
    }

    private loadPlayerPets(): void {
        const saved = localStorage.getItem('tavern_pets');
        if (saved) {
            try {
                const data = JSON.parse(saved);
                this.playerPets = data.pets || [];
                if (data.activePetId) {
                    this.activePet = this.playerPets.find(p => p.id === data.activePetId) || null;
                }
            } catch (error) {
                console.error('[PetSystem] Failed to load pets:', error);
            }
        }
    }

    private savePlayerPets(): void {
        const data = {
            pets: this.playerPets,
            activePetId: this.activePet ? this.activePet.id : null
        };
        localStorage.setItem('tavern_pets', JSON.stringify(data));
    }
}

export default PetSystem;
